cardCss:
/*
 * HOLOGRAPHIC FOIL
 * ─────────────────────────────────────────────────────────────────────────
 * Aesthetic : Collectible holographic trading card — image zone shimmers
 *             with rainbow foil + random sparkle glints + specular sweep
 * Fonts     : Cinzel (title bar, term) · Libre Baskerville (description)
 * Palette   : #0d0d1a dark navy · gold border · silver text · #111118 desc box
 * Layers    : 1. conic-gradient rainbow (color-dodge, animated rotate)
 *             2. SVG feTurbulence sparkle mask (feColorMatrix threshold trick)
 *             3. SVG feTurbulence + feSpecularLighting sweep (fePointLight anim)
 * Back side : same frame, blue-silver metallic sheen only (no full foil)
 */

@import url("https://fonts.googleapis.com/css2?family=Cinzel:wght@400;700&family=Libre+Baskerville:ital,wght@0,400;1,400&display=swap");

:root {
  --hf-navy:   #0d0d1a;
  --hf-gold:   #f0d060;
  --hf-silver: #c0c8d8;
  --hf-title:  #1a1a2e;
  --hf-desc:   #111118;
  --hf-text:   #d0d8e8;
}

html, body, div#qa { height: 100%; }

.card { background: var(--hf-navy); min-height: 100%; }

.off-screen { position: absolute; left: -9999px; }

.holo-card {
  min-height: 100%;
  display: flex;
  flex-direction: column;
  background: var(--hf-navy);
  border: 3px solid transparent;
  background-clip: padding-box;
  box-shadow:
    0 0 0 3px #9a7d3a,
    0 0 0 4px #f0d060,
    0 0 0 5px #c8a84a,
    0 0 14px rgba(240,208,96,0.25);
  box-sizing: border-box;
}

/* ── TITLE BAR ── */
.holo-title-bar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: var(--hf-title);
  padding: 0.5rem 1rem;
  font-family: "Cinzel", serif;
  font-size: 0.9rem;
  letter-spacing: 0.12em;
  color: var(--hf-silver);
  border-bottom: 1px solid #9a7d3a;
}

.holo-rarity { color: var(--hf-gold); letter-spacing: 0.05em; }
.holo-type   { color: var(--hf-gold); font-size: 1.1rem; }

/* ── IMAGE ZONE ── */
.holo-image-zone {
  flex: 1;
  position: relative;
  overflow: hidden;
  min-height: 8rem;
  background: #08081a;
  display: flex;
  align-items: center;
  justify-content: center;
}

.holo-rainbow-layer {
  position: absolute;
  inset: 0;
  z-index: 1;
  background: conic-gradient(
    hsl(0 100% 60%), hsl(60 100% 55%), hsl(120 100% 50%),
    hsl(180 100% 55%), hsl(240 100% 60%), hsl(300 100% 55%), hsl(360 100% 60%)
  );
  mix-blend-mode: color-dodge;
  opacity: 0.35;
  animation: holo-rotate 4s linear infinite;
  pointer-events: none;
}

@keyframes holo-rotate {
  to { transform: rotate(360deg) scale(1.5); }
}

.holo-sparkle-layer {
  position: absolute;
  inset: 0;
  z-index: 2;
  background: #888;
  filter: url(#holo-sparkle);
  mix-blend-mode: screen;
  opacity: 0.6;
  pointer-events: none;
}

.holo-specular-layer {
  position: absolute;
  inset: 0;
  z-index: 3;
  background: #444;
  filter: url(#holo-specular);
  mix-blend-mode: screen;
  opacity: 0.5;
  pointer-events: none;
  animation: holo-delay 5s linear 1.5s infinite;
}

@keyframes holo-delay { from, to { opacity: 0.5; } }

.holo-picture {
  position: relative;
  z-index: 0;
}
.holo-picture img {
  max-width: 100%;
  max-height: 14rem;
  object-fit: contain;
  display: block;
}

.holo-image-zone--back { background: linear-gradient(135deg, #0d0d2a 0%, #1a1a3e 50%, #0d0d2a 100%); }
.holo-image-zone--back::after {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, rgba(160,180,220,0.1) 0%, rgba(200,220,255,0.18) 50%, rgba(100,120,180,0.08) 100%);
  pointer-events: none;
}

/* ── DESC BOX ── */
.holo-desc-box {
  background: var(--hf-desc);
  padding: 1rem 1.2rem;
  border-top: 1px solid #9a7d3a;
  font-family: "Libre Baskerville", serif;
  color: var(--hf-text);
  font-size: 0.9rem;
}

.holo-prompt {
  font-family: "Cinzel", serif;
  font-size: 1rem;
  letter-spacing: 0.12em;
  color: var(--hf-silver);
  margin: 0 0 0.8rem;
  text-transform: uppercase;
}

.holo-term {
  font-family: "Cinzel", serif;
  font-size: 2rem;
  color: var(--hf-gold);
  text-shadow: 0 0 12px rgba(240,208,96,0.4);
  margin: 0 0 0.4rem;
  letter-spacing: 0.08em;
}

.holo-reading    { font-size: 1.2rem; color: var(--hf-silver); margin: 0 0 0.3rem; }
.holo-translation { font-size: 1rem; opacity: 0.85; margin: 0 0 0.2rem; }
.holo-transliteration { font-size: 0.9rem; opacity: 0.65; font-style: italic; margin: 0; }
.holo-tags { font-size: 0.75rem; opacity: 0.45; margin: 0.4rem 0 0; }
.holo-rule { border: none; border-top: 1px solid rgba(160,180,220,0.2); margin: 0.4rem 0; }

.holo-input-wrap { margin-bottom: 0.6rem; }
.holo-input-wrap input {
  font-family: "Cinzel", serif;
  font-size: 1rem;
  background: rgba(255,255,255,0.05);
  border: 1px solid rgba(160,180,220,0.25);
  color: var(--hf-text);
  width: 100%;
  padding: 0.4rem 0.6rem;
  letter-spacing: 0.08em;
  box-sizing: border-box;
}
.holo-input-wrap input:focus { outline: none; border-color: var(--hf-gold); }

.holo-hint-wrap { margin-top: 0.4rem; }
.holo-hint-link { color: rgba(192,200,216,0.4); font-size: 0.8rem; text-decoration: underline; font-family: "Cinzel", serif; }
.holo-hint-text { color: var(--hf-silver); font-size: 0.85rem; margin-top: 0.3rem; }
.holo-audio { margin: 0 0 0.5rem; position: relative; z-index: 2; }

.append-play-btn-text a::after { content: "▶"; color: var(--hf-gold); }
.append-play-btn-text svg { display: none; }
.append-play-btn-text button { font-size: 2rem; cursor: pointer; }
